parameters.jsCode:
const data = $input.first().json.body;

// Handle different message types
if (data.type === 'lead_capture') {
  return [{
    json: {
      type: 'lead_capture',
      data: data
    }
  }];
}

// Regular chat message
return [{
  json: {
    type: 'chat',
    message: data.message,
    history: data.history || [],
    userInfo: data.userInfo || {},
    leadCaptured: data.leadCaptured || false
  }
}];

// Return chat response
return [{
  json: {
    reply: $input.first().json.content
  }
}];

